"use client";

import Image from "next/image";

import {
	Building,
	Building2,
	CircleDashed,
	Code2,
	ImagePlus,
	Lightbulb,
	Megaphone,
	Palette,
	Rocket,
	Sparkles,
	TrendingUp,
} from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
	Dialog,
	DialogContent,
	DialogDescription,
	DialogHeader,
	DialogTitle,
} from "@/components/ui/dialog";
import { cn } from "@/lib/utils";
import {
	ChoiceGroup,
	FeatureCarousel,
	Onboarding,
	TipsList,
	useOnboarding,
} from "../ui/onboarding";

export const STEP_CONFIG = [
	{
		title: "Welcome to Bloom",
		description: "Here's what you can do with Bloom",
	},
	{
		title: "Personalize your experience",
		description: "Bloom will create images tailored to your preferences",
	},
	{
		title: "You're ready to go!",
		description: "A few tips to get the most out of Bloom",
	},
] as const;

export const FEATURES = [
	{
		id: "generate",
		icon: Sparkles,
		title: "Generate any image in seconds",
		description:
			"Describe what you want and watch Bloom create branded visuals in seconds.",
		image: "/images/onboarding-generate.jpg",
	},
	{
		id: "ideas",
		icon: Lightbulb,
		title: "Try ideas from Bloom",
		description:
			"Not sure where to start? Click the lightbulb icon and Bloom will generate ideas for you.",
		image: "/images/onboarding-ideas.jpg",
	},
	{
		id: "upload",
		icon: ImagePlus,
		title: "Add your own images",
		description:
			"Upload your photos and transform them into professional marketing assets.",
		image: "/images/onboarding-upload.jpg",
	},
] as const;

export const ROLES = [
	{ id: "designer", label: "Designer", icon: Palette },
	{ id: "founder", label: "Founder", icon: Rocket },
	{ id: "sales", label: "Sales", icon: TrendingUp },
	{ id: "freelancer", label: "Freelancer", icon: Building2 },
	{ id: "marketing", label: "Marketing", icon: Megaphone },
	{ id: "developer", label: "Developer", icon: Code2 },
	{ id: "agency", label: "Agency", icon: Building },
	{ id: "other", label: "Other", icon: CircleDashed },
] as const;

export const GOALS = [
	{ id: "social-media", label: "Social media content" },
	{ id: "marketing", label: "Marketing materials" },
	{ id: "product", label: "Product photography" },
	{ id: "branding", label: "Brand assets" },
	{ id: "presentations", label: "Presentations" },
	{ id: "other", label: "Something else" },
] as const;

export const TIPS = [
	{ number: 1, text: "Be specific with your prompts for the best results." },
	{ number: 2, text: "Ask for all edits in one prompt to save credits." },
	{
		number: 3,
		text: "Get a credit refund when you provide negative feedback.",
	},
] as const;

export const TOTAL_STEPS = 3;
export const MAX_STEP_VALUE = FEATURES.length - 1;

// ============================================================================
// Headless Primitives Demo (composable, uses shadcn tokens)
// ============================================================================

export function HeadlessOnboardingDemo() {
	const [open, setOpen] = useState(false);
	const [selectedRole, setSelectedRole] = useState<string | null>(null);
	const [selectedGoal, setSelectedGoal] = useState<string | null>(null);

	return (
		<div className="flex flex-col items-center gap-4">
			<p className="text-center text-muted-foreground text-sm">
				Composable primitives: Onboarding, FeatureCarousel, ChoiceGroup,
				TipsList. Uses shadcn design tokens from globals.css.
			</p>
			<Button onClick={() => setOpen(true)} variant="outline">
				Try Headless Onboarding
			</Button>
			<Dialog onOpenChange={setOpen} open={open}>
				<DialogContent
					className="w-full max-w-[calc(100dvw-2rem)] border-none bg-transparent p-0 shadow-none sm:max-w-3xl"
					showCloseButton={false}
				>
					<div className="w-full rounded-2xl bg-muted p-2">
						<Onboarding
							canGoNext={(step) =>
								step === 1 ||
								(step === 2 && selectedRole !== null) ||
								step === 3
							}
							className="relative overflow-hidden"
							maxStepValue={MAX_STEP_VALUE}
							onComplete={() => setOpen(false)}
							totalSteps={3}
						>
							<HeadlessOnboardingHeader />
							<div className="my-8 min-h-[280px]">
								<Onboarding.Step step={1}>
									<HeadlessFeatureStep />
								</Onboarding.Step>
								<Onboarding.Step step={2}>
									<HeadlessRoleStep
										onGoalSelect={setSelectedGoal}
										onRoleSelect={setSelectedRole}
										selectedGoal={selectedGoal}
										selectedRole={selectedRole}
									/>
								</Onboarding.Step>
								<Onboarding.Step step={3}>
									<HeadlessTipsStep />
								</Onboarding.Step>
							</div>
							<Onboarding.Navigation completeLabel="Start Creating" />
						</Onboarding>
					</div>
				</DialogContent>
			</Dialog>
		</div>
	);
}

function HeadlessOnboardingHeader() {
	const { currentStep } = useOnboarding();
	const config = STEP_CONFIG[currentStep - 1];

	return (
		<DialogHeader className="!text-center">
			<DialogTitle className="font-normal font-serif text-3xl text-foreground">
				{config.title}
			</DialogTitle>
			<DialogDescription className="text-base text-muted-foreground">
				{config.description}
			</DialogDescription>
			<div className="pt-3">
				<Onboarding.StepIndicator />
			</div>
		</DialogHeader>
	);
}

function HeadlessFeatureStep() {
	const { stepValue, setStepValue } = useOnboarding();

	return (
		<div className="flex flex-col gap-4 md:flex-row md:gap-6">
			<FeatureCarousel
				className="order-2 flex w-full flex-col gap-3 md:order-1 md:w-1/2"
				onValueChange={setStepValue}
				totalItems={FEATURES.length}
				value={stepValue}
			>
				{FEATURES.map((feature, index) => {
					const Icon = feature.icon;
					const isActive = stepValue === index;
					return (
						<FeatureCarousel.Item index={index} key={feature.id}>
							<div
								className={cn(
									"flex items-start gap-3 rounded-xl border p-4 text-left transition-all duration-200",
									isActive
										? "border-primary/30 bg-primary/10"
										: "border-transparent hover:bg-muted",
								)}
							>
								<Icon
									className={cn(
										"mt-0.5 size-5 shrink-0",
										isActive ? "text-primary" : "text-muted-foreground",
									)}
								/>
								<div>
									<p className="font-medium text-foreground text-sm">
										{feature.title}
									</p>
									{isActive && (
										<p className="mt-1 text-muted-foreground text-sm leading-relaxed">
											{feature.description}
										</p>
									)}
								</div>
							</div>
						</FeatureCarousel.Item>
					);
				})}
			</FeatureCarousel>
			<div className="order-1 w-full md:order-2 md:w-1/2">
				<div className="relative aspect-[4/3] overflow-hidden rounded-xl border bg-muted">
					<Image
						alt={FEATURES[stepValue].title}
						className="object-cover transition-opacity duration-300"
						fill
						sizes="(max-width: 768px) 100vw, 40vw"
						src={FEATURES[stepValue].image}
					/>
				</div>
			</div>
		</div>
	);
}

function HeadlessRoleStep({
	selectedRole,
	onRoleSelect,
	selectedGoal,
	onGoalSelect,
}: {
	selectedRole: string | null;
	onRoleSelect: (v: string) => void;
	selectedGoal: string | null;
	onGoalSelect: (v: string) => void;
}) {
	const [question, setQuestion] = useState(1);

	return (
		<div className="flex flex-col gap-4">
			{question === 1 ? (
				<div className="flex flex-col gap-4" key="q1">
					<div className="flex items-center gap-2">
						<span className="inline-flex size-6 items-center justify-center rounded-lg bg-muted text-muted-foreground text-sm">
							1
						</span>
						<span className="font-medium text-base text-foreground">
							What best describes you?
						</span>
					</div>
					<ChoiceGroup
						className="grid grid-cols-2 gap-2 sm:gap-3 md:grid-cols-3"
						name="Select your role"
						onValueChange={(v) => {
							onRoleSelect(v);
							setTimeout(() => setQuestion(2), 300);
						}}
						orientation="grid"
						value={selectedRole}
					>
						{ROLES.map((role) => {
							const Icon = role.icon;
							const isSelected = selectedRole === role.id;
							return (
								<ChoiceGroup.Item
									className={cn(
										"flex items-center gap-2.5 rounded-xl border px-4 py-3 text-left text-sm transition-all duration-200",
										isSelected
											? "border-primary/30 bg-primary/10 text-foreground"
											: "border-border bg-background text-foreground hover:bg-muted",
									)}
									key={role.id}
									value={role.id}
								>
									<Icon className="size-4 shrink-0 text-muted-foreground" />
									<span>{role.label}</span>
								</ChoiceGroup.Item>
							);
						})}
					</ChoiceGroup>
					<p className="text-muted-foreground text-sm">Question 1 of 2</p>
				</div>
			) : (
				<div className="flex flex-col gap-4" key="q2">
					<div className="flex items-center gap-2">
						<span className="inline-flex size-6 items-center justify-center rounded-lg bg-muted text-muted-foreground text-sm">
							2
						</span>
						<span className="font-medium text-base text-foreground">
							What do you want to create?
						</span>
					</div>
					<ChoiceGroup
						className="grid grid-cols-2 gap-2 sm:gap-3"
						name="Select your goal"
						onValueChange={onGoalSelect}
						orientation="grid"
						value={selectedGoal}
					>
						{GOALS.map((goal) => {
							const isSelected = selectedGoal === goal.id;
							return (
								<ChoiceGroup.Item
									className={cn(
										"flex items-center gap-2.5 rounded-xl border px-4 py-3 text-left text-sm transition-all duration-200",
										isSelected
											? "border-primary/30 bg-primary/10 text-foreground"
											: "border-border bg-background text-foreground hover:bg-muted",
									)}
									key={goal.id}
									value={goal.id}
								>
									<span>{goal.label}</span>
								</ChoiceGroup.Item>
							);
						})}
					</ChoiceGroup>
					<div className="flex items-center justify-between">
						<p className="text-muted-foreground text-sm">Question 2 of 2</p>
						<button
							className="text-muted-foreground text-sm transition-colors hover:text-foreground"
							onClick={() => setQuestion(1)}
							type="button"
						>
							Back to question 1
						</button>
					</div>
				</div>
			)}
		</div>
	);
}

function HeadlessTipsStep() {
	return (
		<div className="flex flex-col items-start gap-4 md:flex-row md:gap-6">
			<div className="order-2 w-full md:order-1 md:w-1/2">
				<TipsList
					className="flex flex-col gap-4 [&_[data-slot=tips-list-title]]:not-sr-only [&_[data-slot=tips-list-title]]:mb-4 [&_[data-slot=tips-list-title]]:font-semibold [&_[data-slot=tips-list-title]]:text-muted-foreground [&_[data-slot=tips-list-title]]:text-xs [&_[data-slot=tips-list-title]]:uppercase [&_[data-slot=tips-list-title]]:tracking-wider"
					title="Tips"
				>
					{TIPS.map((tip) => (
						<TipsList.Item
							className="flex items-start gap-3 [&_[data-slot=tips-list-item-number]]:inline-flex [&_[data-slot=tips-list-item-number]]:size-6 [&_[data-slot=tips-list-item-number]]:shrink-0 [&_[data-slot=tips-list-item-number]]:items-center [&_[data-slot=tips-list-item-number]]:justify-center [&_[data-slot=tips-list-item-number]]:rounded-lg [&_[data-slot=tips-list-item-number]]:bg-muted [&_[data-slot=tips-list-item-number]]:text-muted-foreground [&_[data-slot=tips-list-item-number]]:text-sm"
							key={tip.number}
							number={tip.number}
						>
							<p className="text-foreground text-sm leading-relaxed">
								{tip.text}
							</p>
						</TipsList.Item>
					))}
				</TipsList>
			</div>
			<div className="order-1 w-full md:order-2 md:w-1/2">
				<div className="flex aspect-video w-full items-center justify-center rounded-xl border bg-background md:aspect-[4/3]">
					<svg
						aria-hidden
						className="text-foreground"
						fill="none"
						height="120"
						viewBox="0 0 120 120"
						width="120"
						xmlns="http://www.w3.org/2000/svg"
					>
						<title>Bloom logo</title>
						<path
							d="M60 20C40 20 25 40 25 55C25 70 35 85 50 90L55 95C55 100 50 105 50 105C50 105 60 100 65 95L70 90C85 85 95 70 95 55C95 40 80 20 60 20Z"
							fill="currentColor"
							opacity="0.15"
							stroke="currentColor"
							strokeLinecap="round"
							strokeLinejoin="round"
							strokeWidth="4"
						/>
						<circle
							cx="58"
							cy="78"
							fill="none"
							r="5"
							stroke="currentColor"
							strokeWidth="3"
						/>
						<path
							d="M56 83C52 90 48 95 48 95"
							stroke="currentColor"
							strokeLinecap="round"
							strokeWidth="3"
						/>
					</svg>
				</div>
			</div>
		</div>
	);
}
